abstract class Animal {
  String name;

  Animal(this.name);

  // Abstract method – no body
  void makeSound();

  // Concrete method
  void sleep() {
    print('$name is sleeping.');
  }
}

class Dog extends Animal {
  Dog(String name) : super(name);

  @override
  void makeSound() {
    print('$name barks.');
  }
}

void main() {
  // Animal a = Animal('pet'); // Error: Cannot instantiate abstract class
  Dog dog = Dog('Buddy');
  dog.makeSound(); // Buddy barks.
  dog.sleep();     // Buddy is sleeping.
}

abstract class Shape {
  double area(); // abstract method

  void display() {
    print('Area: ${area()}');
  }
}

class Circle extends Shape {
  double radius;

  Circle(this.radius);

  @override
  double area() => 3.14 * radius * radius;
}

class Flyable {
  void fly() {}
}

class Bird implements Flyable {
  @override
  void fly() {
    print('Bird flies');
  }
}

class Airplane implements Flyable {
  @override
  void fly() {
    print('Airplane flies');
  }
}

class Swimmable {
  void swim() {}
}

class Walkable {
  void walk() {}
}

class Duck implements Swimmable, Walkable {
  @override
  void swim() {
    print('Duck swims');
  }

  @override
  void walk() {
    print('Duck walks');
  }
}

abstract class Shape {
  factory Shape(String type) {
    if (type == 'circle') return Circle(5);
    if (type == 'square') return Square(4);
    throw ArgumentError('Unknown shape type');
  }

  double area();
}

class Circle implements Shape {
  double radius;
  Circle(this.radius);
  @override
  double area() => 3.14 * radius * radius;
}

class Square implements Shape {
  double side;
  Square(this.side);
  @override
  double area() => side * side;
}

void main() {
  Shape shape = Shape('circle');
  print(shape.area()); // 78.5
}

abstract class PaymentProcessor {
  void processPayment(double amount);

  void validateAmount(double amount) {
    if (amount <= 0) {
      throw ArgumentError('Amount must be positive');
    }
  }
}

class CreditCardProcessor extends PaymentProcessor {
  @override
  void processPayment(double amount) {
    validateAmount(amount);
    print('Processing credit card payment of \$$amount');
  }
}

class PayPalProcessor extends PaymentProcessor {
  @override
  void processPayment(double amount) {
    validateAmount(amount);
    print('Processing PayPal payment of \$$amount');
  }
}

void main() {
  PaymentProcessor processor = CreditCardProcessor();
  processor.processPayment(100.0);

  processor = PayPalProcessor();
  processor.processPayment(200.0);
}

